#pragma once

#include <cuda_runtime.h>
#include <stdint.h>
#include <math_constants.h>

// Fixed vocabulary size for Qwen3
constexpr int VOCAB_SIZE = 151936;

// Kernel configuration constants optimized for A800
constexpr int THREADS_PER_BLOCK = 128;
constexpr int LOCAL_TOP_K = 32;  // Top-k per thread for local selection
constexpr int MAX_SHARED_TOP_K = 256;  // Maximum top-k we can store in shared memory

/**
 * Top-k sampling kernel for probability distributions
 * 
 * @param probs Input probability distributions [batch_size, vocab_size]
 * @param top_k Number of top tokens to consider per sequence [batch_size]
 * @param samples Output sampled token indices [batch_size]
 * @param batch_size Number of sequences to sample from
 */
__global__ void top_k_sampling_kernel(
    const float* __restrict__ probs,
    const int* __restrict__ top_k,
    int64_t* __restrict__ samples,
    int batch_size
);

/**
 * Host function to launch the top-k sampling kernel
 * 
 * @param probs Device pointer to probability distributions
 * @param top_k Device pointer to top-k values
 * @param samples Device pointer for output samples
 * @param batch_size Number of sequences
 * @param stream CUDA stream for asynchronous execution
 * @return cudaError_t Error code
 */
cudaError_t launch_top_k_sampling_kernel(
    const float* probs,
    const int* top_k,
    int64_t* samples,
    int batch_size,
    cudaStream_t stream = 0
);

// Device-side random number generator using LCG
__device__ __forceinline__ float device_rand(unsigned long long& state) {
    state = state * 6364136223846793005ULL + 1442695040888963407ULL;
    return (float)(state >> 32) / 4294967296.0f;
}

#include "kernel.h"
#include <math_constants.h>

/**
 * Main top-k sampling kernel
 * Each block processes one batch element
 * 
 * Algorithm:
 * 1. Each thread processes a portion of vocabulary
 * 2. Find local top-k values per thread
 * 3. Merge local top-k to global top-k using reduction
 * 4. Normalize top-k probabilities
 * 5. Sample from top-k distribution using inverse transform
 */
__global__ void top_k_sampling_kernel(
    const float* __restrict__ probs,
    const int* __restrict__ top_k,
    int64_t* __restrict__ samples,
    int batch_size
) {
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    int tid = threadIdx.x;
    int threads_in_block = blockDim.x;

    // Get row pointer and k value
    const float* row = probs + batch_idx * VOCAB_SIZE;
    int k = top_k[batch_idx];

    // Validate and cap k
    if (k <= 0) k = 1;
    if (k >= VOCAB_SIZE) k = VOCAB_SIZE;
    int effective_k = min(k, MAX_SHARED_TOP_K);

    // Shared memory for local top-k results from each thread
    __shared__ float thread_top_k_values[THREADS_PER_BLOCK * LOCAL_TOP_K];
    __shared__ int thread_top_k_indices[THREADS_PER_BLOCK * LOCAL_TOP_K];

    // Each thread finds its local top-k from its portion of vocabulary
    int vocab_per_thread = (VOCAB_SIZE + threads_in_block - 1) / threads_in_block;
    int vocab_start = tid * vocab_per_thread;
    int vocab_end = min(vocab_start + vocab_per_thread, VOCAB_SIZE);

    float* my_local_values = thread_top_k_values + tid * LOCAL_TOP_K;
    int* my_local_indices = thread_top_k_indices + tid * LOCAL_TOP_K;

    // Initialize local top-k with minimum values
    for (int i = 0; i < LOCAL_TOP_K; i++) {
        my_local_values[i] = -1.0f;
        my_local_indices[i] = -1;
    }

    // Process each value in this thread's range with coalesced access
    for (int i = vocab_start; i < vocab_end; i++) {
        float val = row[i];
        int idx = i;

        // Find insertion position in local top-k (sorted descending)
        int insert_pos = -1;
        for (int j = 0; j < LOCAL_TOP_K; j++) {
            if (val > my_local_values[j]) {
                insert_pos = j;
                break;
            }
        }

        if (insert_pos >= 0) {
            // Shift down
            for (int m = LOCAL_TOP_K - 1; m > insert_pos; m--) {
                my_local_values[m] = my_local_values[m - 1];
                my_local_indices[m] = my_local_indices[m - 1];
            }
            my_local_values[insert_pos] = val;
            my_local_indices[insert_pos] = idx;
        }
    }

    __syncthreads();

    // Shared memory for global top-k results
    __shared__ float global_top_k_values[MAX_SHARED_TOP_K];
    __shared__ int global_top_k_indices[MAX_SHARED_TOP_K];

    // Thread 0 collects and merges all local top-k lists
    if (tid == 0) {
        // Initialize global top-k
        for (int i = 0; i < effective_k; i++) {
            global_top_k_values[i] = -1.0f;
            global_top_k_indices[i] = -1;
        }

        // Merge from all threads
        for (int t = 0; t < threads_in_block; t++) {
            float* t_values = thread_top_k_values + t * LOCAL_TOP_K;
            int* t_indices = thread_top_k_indices + t * LOCAL_TOP_K;

            for (int j = 0; j < LOCAL_TOP_K; j++) {
                if (t_values[j] < 0.0f) continue;

                // Insert into global top-k
                int insert_pos = -1;
                for (int m = 0; m < effective_k; m++) {
                    if (t_values[j] > global_top_k_values[m]) {
                        insert_pos = m;
                        break;
                    }
                }

                if (insert_pos >= 0) {
                    // Shift down
                    for (int m = effective_k - 1; m > insert_pos; m--) {
                        global_top_k_values[m] = global_top_k_values[m - 1];
                        global_top_k_indices[m] = global_top_k_indices[m - 1];
                    }
                    global_top_k_values[insert_pos] = t_values[j];
                    global_top_k_indices[insert_pos] = t_indices[j];
                }
            }
        }
    }

    __syncthreads();

    // Thread 0 performs sampling from top-k distribution
    if (tid == 0) {
        // Calculate sum of top-k probabilities
        float sum = 0.0f;
        int valid_count = 0;
        for (int i = 0; i < effective_k; i++) {
            if (global_top_k_indices[i] >= 0) {
                sum += global_top_k_values[i];
                valid_count++;
            }
        }

        // Handle edge case where sum is zero or no valid indices
        if (sum <= 0.0f || valid_count == 0) {
            // Uniform sampling from valid indices
            unsigned long long state = (unsigned long long)batch_idx * 12345ULL + 67890ULL;
            float rand_val = device_rand(state);
            int selected_idx = (int)(rand_val * valid_count);
            if (selected_idx >= valid_count) selected_idx = valid_count - 1;
            if (selected_idx >= 0 && selected_idx < valid_count) {
                samples[batch_idx] = global_top_k_indices[selected_idx];
            } else {
                samples[batch_idx] = 0;
            }
        } else {
            // Generate random number for sampling
            unsigned long long state = (unsigned long long)batch_idx * 12345ULL + 67890ULL;
            float rand_val = device_rand(state);

            // Inverse transform sampling with normalization
            float cumsum = 0.0f;
            int selected = -1;
            for (int i = 0; i < effective_k; i++) {
                if (global_top_k_indices[i] < 0) continue;
                float normalized_val = global_top_k_values[i] / sum;
                cumsum += normalized_val;

                if (rand_val < cumsum) {
                    selected = global_top_k_indices[i];
                    break;
                }
            }

            // Fallback to last valid index
            if (selected < 0) {
                for (int i = effective_k - 1; i >= 0; i--) {
                    if (global_top_k_indices[i] >= 0) {
                        selected = global_top_k_indices[i];
                        break;
                    }
                }
            }

            samples[batch_idx] = selected >= 0 ? selected : 0;
        }
    }
}

/**
 * Host function to launch the kernel with optimal configuration
 * Uses static shared memory - no dynamic shared memory parameter needed
 */
cudaError_t launch_top_k_sampling_kernel(
    const float* probs,
    const int* top_k,
    int64_t* samples,
    int batch_size,
    cudaStream_t stream
) {
    // Configure kernel launch
    int blocks = batch_size;  // One block per batch element
    int threads = THREADS_PER_BLOCK;

    // Launch kernel
    top_k_sampling_kernel<<<blocks, threads, 0, stream>>>(
        probs, top_k, samples, batch_size
    );

    return cudaGetLastError();
}

#include <torch/extension.h>
#include <torch/script.h>
#include <ATen/ATen.h>
#include <ATen/cuda/CUDAContext.h>
#include "kernel.h"
#include <cuda_runtime.h>
#include <stdexcept>
#include <string>
#include <vector>

/**
 * Validate tensor properties
 */
void validate_tensor(const torch::Tensor& tensor, const std::string& name, 
                     torch::Dtype expected_dtype, torch::DeviceType expected_device,
                     const std::vector<int64_t>& expected_shape = {}) {
    if (!tensor.device().is_cuda()) {
        throw std::runtime_error(name + " must be on CUDA device");
    }

    if (tensor.dtype() != expected_dtype) {
        std::string dtype_str = expected_dtype == torch::kFloat32 ? "float32" :
                                expected_dtype == torch::kInt32 ? "int32" :
                                expected_dtype == torch::kInt64 ? "int64" : "unknown";
        throw std::runtime_error(name + " must have dtype " + dtype_str);
    }

    if (!expected_shape.empty() && tensor.dim() != expected_shape.size()) {
        throw std::runtime_error(name + " has incorrect number of dimensions");
    }

    for (size_t i = 0; i < expected_shape.size(); i++) {
        if (expected_shape[i] > 0 && tensor.size(i) != expected_shape[i]) {
            throw std::runtime_error(name + " has incorrect shape at dimension " + 
                                   std::to_string(i) + ": expected " + 
                                   std::to_string(expected_shape[i]) + ", got " +
                                   std::to_string(tensor.size(i)));
        }
    }
}

/**
 * Main run function for top-k sampling
 */
torch::Tensor run(
    const torch::Tensor& probs,
    const torch::Tensor& top_k,
    torch::Tensor samples
) {
    // Validate inputs
    validate_tensor(probs, "probs", torch::kFloat32, torch::kCUDA, {0, VOCAB_SIZE});
    validate_tensor(top_k, "top_k", torch::kInt32, torch::kCUDA, {0});

    // Check batch size consistency
    int64_t batch_size = probs.size(0);
    if (top_k.size(0) != batch_size) {
        throw std::runtime_error("top_k batch size must match probs batch size");
    }

    // Check vocab size
    if (probs.size(1) != VOCAB_SIZE) {
        throw std::runtime_error("vocab_size must be " + std::to_string(VOCAB_SIZE) +
                               ", got " + std::to_string(probs.size(1)));
    }

    // Create output tensor if not provided
    if (samples.numel() == 0) {
        samples = torch::empty(
            {batch_size},
            torch::TensorOptions().dtype(torch::kInt64).device(torch::kCUDA)
        );
    } else {
        // Validate output tensor
        if (samples.size(0) != batch_size) {
            throw std::runtime_error("samples tensor size must match batch size");
        }
        if (samples.dtype() != torch::kInt64) {
            throw std::runtime_error("samples tensor must have dtype int64");
        }
        if (!samples.device().is_cuda()) {
            throw std::runtime_error("samples tensor must be on CUDA device");
        }
    }

    // Get raw pointers
    const float* probs_ptr = probs.data_ptr<float>();
    const int* top_k_ptr = top_k.data_ptr<int>();
    int64_t* samples_ptr = samples.data_ptr<int64_t>();

    // Get CUDA stream
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    // Launch kernel
    cudaError_t err = launch_top_k_sampling_kernel(
        probs_ptr, top_k_ptr, samples_ptr, 
        static_cast<int>(batch_size), stream
    );

    if (err != cudaSuccess) {
        throw std::runtime_error("CUDA kernel launch failed: " + 
                               std::string(cudaGetErrorString(err)));
    }

    // Synchronize to ensure completion
    err = cudaStreamSynchronize(stream);
    if (err != cudaSuccess) {
        throw std::runtime_error("CUDA stream synchronization failed: " + 
                               std::string(cudaGetErrorString(err)));
    }

    return samples;
}

/**
 * PyBind11 module definition
 */
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "Top-k sampling kernel optimized for A800 GPU";
    m.def("run", &run, 
          "Perform top-k sampling from probability distributions",
          py::arg("probs"),
          py::arg("top_k"),
          py::arg("samples") = torch::Tensor());
}
